import { useEffect, useState } from 'react'

/**
 * Use relative /api/* URLs so Vite's dev server proxies to the Express app on 4000.
 * Do not point the browser at http://localhost:4000 in assessment preview — only 5173 is exposed.
 */
export function App() {
  const [status, setStatus] = useState<'loading' | 'ok' | 'error'>('loading')
  const [message, setMessage] = useState<string>('')

  useEffect(() => {
    let cancelled = false
    ;(async () => {
      try {
        const r = await fetch('/api/health')
        const j = (await r.json().catch(() => ({}))) as { ok?: boolean }
        if (cancelled) return
        if (r.ok && j?.ok) {
          setStatus('ok')
          setMessage('API reachable via Vite proxy.')
        } else {
          setStatus('error')
          setMessage(`HTTP ${r.status}`)
        }
      } catch (e) {
        if (cancelled) return
        setStatus('error')
        setMessage(e instanceof Error ? e.message : 'Request failed')
      }
    })()
    return () => {
      cancelled = true
    }
  }, [])

  return (
    <main>
      <h1>Full-stack template</h1>
      <p>
        {status === 'loading' && 'Checking /api/health…'}
        {status === 'ok' && <span style={{ color: 'green' }}>{message}</span>}
        {status === 'error' && (
          <span style={{ color: 'crimson' }}>
            {message} — run <code>npm run dev</code> from the repo root (Vite + API), then use Preview →
            Reload.
          </span>
        )}
      </p>
    </main>
  )
}

