import { defineConfig } from 'vite'
import react from '@vitejs/plugin-react'

// HMR routing through code-server's /proxy/{port}/ tunnel.
//
// PROMORA_IDE_HOST_PORT  — the host port for code-server (e.g. 18082).
//   HMR WebSocket goes:  browser → ws://localhost:<ide> → code-server → /proxy/5173/ → Vite.
//
// PROMORA_PREVIEW_HOST_PORT — the host port mapped directly to :5173.
//   Used as fallback if IDE port is not available.
const idePort     = process.env.PROMORA_IDE_HOST_PORT
  ? Number(process.env.PROMORA_IDE_HOST_PORT)
  : undefined
const previewPort = process.env.PROMORA_PREVIEW_HOST_PORT
  ? Number(process.env.PROMORA_PREVIEW_HOST_PORT)
  : undefined

function hmrConfig() {
  if (idePort) {
    // Route HMR WebSocket through code-server proxy — same path as the preview iframe
    return { host: 'localhost', clientPort: idePort, path: '/proxy/5173/', protocol: 'ws' as const }
  }
  if (previewPort) {
    // Route HMR WebSocket through the directly-mapped port
    return { host: 'localhost', clientPort: previewPort, protocol: 'ws' as const }
  }
  // Local dev without Docker — HMR on same host/port
  return true
}

export default defineConfig({
  plugins: [react()],
  server: {
    port: 5173,
    host: '0.0.0.0',
    strictPort: true,
    hmr: hmrConfig(),
    proxy: {
      '/api': {
        target: 'http://127.0.0.1:4000',
        changeOrigin: true,
      },
    },
  },
})

